import{_ as a,o as e,c as n,a2 as t}from"./chunks/framework.CH-YxFqP.js";const b=JSON.parse('{"title":"架构与特性","description":"","frontmatter":{},"headers":[],"relativePath":"reference/architecture.md","filePath":"reference/architecture.md","lastUpdated":1781350447000}'),i={name:"reference/architecture.md"};function l(p,s,r,d,o,c){return e(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="架构与特性" tabindex="-1">架构与特性 <a class="header-anchor" href="#架构与特性" aria-label="Permalink to &quot;架构与特性&quot;">​</a></h1><p>Nginx-Reverse-Emby 是面向 Emby、Jellyfin 以及 HTTP/TCP 服务的纯 Go 反向代理控制面。默认部署路径是 Docker Compose 启动控制面，并启用内嵌 <code>local</code> agent 执行代理规则。</p><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><ul><li>纯 Go 运行时：控制面和执行面不依赖 Nginx。</li><li>可视化面板：管理 HTTP 规则、L4 规则、Relay 监听器、证书和 Agent。</li><li>自动化 SSL：支持 ACME HTTP/DNS 验证和证书续期。</li><li>Master/Agent 架构：集中管理多节点，Agent 通过心跳拉取配置。</li><li>全栈协议：HTTP/HTTPS、L4 TCP/UDP、Relay、WireGuard、HTTP/3、IPv4/IPv6。</li><li>流式恢复：HTTP 代理内置中断流恢复和 backend 重试机制。</li><li>版本管理：控制面可向 Agent 下发 <code>desired_version</code>。</li></ul><h2 id="运行结构" tabindex="-1">运行结构 <a class="header-anchor" href="#运行结构" aria-label="Permalink to &quot;运行结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Master 控制面</span></span>
<span class="line"><span>├─ Vue 3 SPA</span></span>
<span class="line"><span>├─ Go Control Plane</span></span>
<span class="line"><span>│  ├─ REST API</span></span>
<span class="line"><span>│  ├─ Agent 注册和管理</span></span>
<span class="line"><span>│  ├─ 规则、证书、Relay 存储</span></span>
<span class="line"><span>│  └─ 版本策略下发</span></span>
<span class="line"><span>├─ local agent</span></span>
<span class="line"><span>│  ├─ HTTP 代理引擎</span></span>
<span class="line"><span>│  ├─ L4 代理</span></span>
<span class="line"><span>│  └─ Relay</span></span>
<span class="line"><span>└─ SQLite / PostgreSQL / MySQL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>远程 Agent 通过 heartbeat pull 主动向 Master 同步期望状态。NAT 节点只需要能访问 Master，不要求 Master 能主动连进 Agent。</p><h2 id="数据存储" tabindex="-1">数据存储 <a class="header-anchor" href="#数据存储" aria-label="Permalink to &quot;数据存储&quot;">​</a></h2><p>Docker Compose 默认使用 SQLite，数据目录挂载到宿主机 <code>./data</code>。如果要切到 PostgreSQL 或 MySQL，可通过 <code>NRE_DATABASE_DRIVER</code> 和 <code>NRE_DATABASE_DSN</code> 配置。</p><p>普通新手部署无需改数据库，保持默认 SQLite 即可。</p><h2 id="默认-compose-为什么使用-host-网络" tabindex="-1">默认 Compose 为什么使用 host 网络 <a class="header-anchor" href="#默认-compose-为什么使用-host-网络" aria-label="Permalink to &quot;默认 Compose 为什么使用 host 网络&quot;">​</a></h2><p>面板中的 HTTP、L4、Relay 监听端口是动态创建的。Docker bridge 网络无法在容器运行后自动发布新增端口，所以默认 Compose 使用 host 网络，让 <code>local</code> agent 直接绑定宿主机端口。</p><p>这也意味着你在规则里填写的监听端口会直接占用 VPS 端口，需要提前检查端口冲突并放行防火墙。</p><h2 id="legacy-deploy-sh" tabindex="-1">legacy deploy.sh <a class="header-anchor" href="#legacy-deploy-sh" aria-label="Permalink to &quot;legacy deploy.sh&quot;">​</a></h2><p><code>deploy.sh</code>、<code>conf.d/</code> 和仓库根目录 <code>nginx.conf</code> 是历史独立 Nginx 工作流，不是当前默认控制面路径。</p><p>仍需使用主机 Nginx 模式时，可以执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sakullla/nginx-reverse-emby/main/deploy.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>非交互添加规则示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sakullla/nginx-reverse-emby/main/deploy.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://emby.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8096</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>常用参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><code>-y, --you-domain</code></td><td>前端访问地址。</td></tr><tr><td><code>-r, --r-domain</code></td><td>后端目标地址。</td></tr><tr><td><code>-m, --cert-domain</code></td><td>手动指定证书主域名。</td></tr><tr><td><code>-d, --parse-cert-domain</code></td><td>自动提取根域名作为证书域名。</td></tr><tr><td><code>-D, --dns</code></td><td>使用 DNS API 模式申请证书。</td></tr><tr><td><code>--no-proxy-redirect</code></td><td>禁用 302/307 重定向代理。</td></tr><tr><td><code>--remove</code></td><td>移除指定域名配置。</td></tr><tr><td><code>-Y, --yes</code></td><td>非交互模式自动确认。</td></tr></tbody></table>`,21)])])}const k=a(i,[["render",l]]);export{b as __pageData,k as default};
